function FloatingParticle({ emoji, delay, duration, x }) {
  return (
    <span style={{
      position: 'absolute', fontSize: 18, opacity: 0,
      left: `${x}%`, bottom: '-20px',
      animation: `floatUp ${duration}s ease-in ${delay}s infinite`,
      pointerEvents: 'none', userSelect: 'none', zIndex: 2,
    }}>{emoji}</span>
  )
}

function SystemCard({ sys, idx }) {
  const navigate = useNavigate()
  const [hovered, setHovered] = useState(false)
  const [clicked, setClicked] = useState(false)

  const handleClick = () => {
    if (!sys.available) return
    setClicked(true)
    setTimeout(() => navigate(sys.route), 400)
  }

  const particles = sys.particles.map((e, i) => ({
    emoji: e, delay: i * 0.7, duration: 3 + i * 0.4, x: 10 + i * 18
  }))

  return (
    <div onClick={handleClick} onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      style={{
        position: 'relative', overflow: 'hidden', borderRadius: 24, padding: '28px 24px 24px',
        cursor: sys.available ? 'pointer' : 'default',
        border: `1px solid ${hovered && sys.available ? sys.accent : 'rgba(255,255,255,0.1)'}`,
        background: hovered && sys.available
          ? `linear-gradient(145deg, ${sys.accent}25, rgba(0,0,0,0.6))`
          : 'rgba(0,0,0,0.45)',
        backdropFilter: 'blur(20px)',
        WebkitBackdropFilter: 'blur(20px)',
        transform: clicked ? 'scale(0.97)' : hovered && sys.available ? 'translateY(-8px)' : 'translateY(0)',
        transition: 'all 0.35s cubic-bezier(0.34,1.56,0.64,1)',
        boxShadow: hovered && sys.available
          ? `0 24px 60px ${sys.glow}, 0 0 0 1px ${sys.accent}50`
          : '0 8px 32px rgba(0,0,0,0.4)',
        animation: `cardIn 0.6s ease ${idx * 0.15}s both`,
        display: 'flex', flexDirection: 'column', minHeight: 320,
      }}>
      <div style={{ position:'absolute', top:0, left:0, right:0, height:3, zIndex:2, background:`linear-gradient(90deg, transparent, ${sys.accent}, transparent)`, opacity: hovered ? 1 : 0.5, transition:'opacity 0.3s' }}/>
      {hovered && sys.available && (
        <div style={{ position:'absolute', inset:0, pointerEvents:'none', zIndex:1, background:`linear-gradient(105deg, transparent 30%, ${sys.accent}15 50%, transparent 70%)`, animation:'shimmer 1.5s linear infinite' }}/>
      )}
      {hovered && sys.available && particles.map((p, i) => <FloatingParticle key={i} {...p}/>)}

      <div style={{ position:'absolute', top:14, right:14, zIndex:3, background:`${sys.badgeColor}25`, border:`1px solid ${sys.badgeColor}60`, color:sys.badgeColor, fontSize:9, fontWeight:800, letterSpacing:'0.12em', padding:'3px 10px', borderRadius:99 }}>{sys.badge}</div>

      <div style={{ position:'relative', zIndex:1, width:64, height:64, borderRadius:18, background:`linear-gradient(135deg, ${sys.accent}35, ${sys.accent}12)`, border:`1px solid ${sys.accent}50`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:28, marginBottom:18, boxShadow: hovered ? `0 8px 24px ${sys.glow}` : 'none', transition:'box-shadow 0.3s', animation: hovered && sys.available ? 'iconPulse 1s ease infinite' : 'none' }}>{sys.icon}</div>

      <h3 style={{ position:'relative', zIndex:1, color:'#fff', fontSize:17, fontWeight:800, margin:'0 0 5px', fontFamily:"'Playfair Display',serif", lineHeight:1.3, textShadow:'0 2px 8px rgba(0,0,0,0.6)' }}>{sys.title}</h3>
      <p style={{ position:'relative', zIndex:1, color:sys.accent, fontSize:10, fontWeight:700, letterSpacing:'0.08em', margin:'0 0 12px', textTransform:'uppercase' }}>{sys.subtitle}</p>
      <p style={{ position:'relative', zIndex:1, color:'rgba(255,255,255,0.75)', fontSize:13, lineHeight:1.6, margin:'0 0 18px', flex:1 }}>{sys.desc}</p>

      <div style={{ position:'relative', zIndex:1, display:'flex', gap:6, flexWrap:'wrap', marginBottom:18 }}>
        {sys.tags.map(tag => (
          <span key={tag} style={{ fontSize:10, padding:'3px 10px', borderRadius:99, background:'rgba(0,0,0,0.4)', border:`1px solid ${sys.accent}40`, color:'rgba(255,255,255,0.8)', fontWeight:600, backdropFilter:'blur(4px)' }}>{tag}</span>
        ))}
      </div>

      <div style={{ position:'relative', zIndex:1, display:'flex', alignItems:'center', gap:8, padding:'11px 18px', borderRadius:12, background: sys.available ? (hovered ? sys.accent : 'rgba(0,0,0,0.5)') : 'rgba(0,0,0,0.3)', border:`1px solid ${sys.available ? sys.accent+'70' : 'rgba(255,255,255,0.08)'}`, color: sys.available ? '#fff' : 'rgba(255,255,255,0.35)', fontWeight:700, fontSize:13, transition:'all 0.3s', justifyContent:'center', backdropFilter:'blur(8px)' }}>
        {sys.available ? <><span>→</span> Konekte Kounye a</> : <><span>🔒</span> Byento Disponib</>}
      </div>
    </div>
  )
}

function FeatureCard({ f, idx }) {
  return (
    <div style={{ padding:'22px 20px', borderRadius:16, background:'rgba(0,0,0,0.4)', border:'1px solid rgba(255,255,255,0.08)', backdropFilter:'blur(12px)', animation:`cardIn 0.5s ease ${idx*0.08}s both` }}>
      <div style={{ fontSize:28, marginBottom:12 }}>{f.icon}</div>
      <h4 style={{ color:'#fff', fontSize:14, fontWeight:700, margin:'0 0 8px', fontFamily:"'Playfair Display',serif" }}>{f.title}</h4>
      <p style={{ color:'rgba(255,255,255,0.55)', fontSize:12, lineHeight:1.6, margin:0 }}>{f.desc}</p>
    </div>
  )
}

